import Button from "../../components/Login/Button";
import Dropdown from "../../components/Login/Dropdown";
import Input from "../../components/Login/Input";
import TextButton from "../../components/Login/TextButton";
import classes from "./Login.module.css";

const Register = () => {
  const onSubmitHandler = (event) => {
    event.preventDefault();
    console.log("Registering");
  };

  return (
    <div className={classes["wrapper"]}>
      <form className={classes["form"]} onSubmit={onSubmitHandler}>
        <div className={classes["header"]}>
          <h1 className={classes["heading"]}>Create an account </h1>
        </div>
        <div className={classes["block"]}>
          <Input name="email" label="email" type="text"></Input>
          <Input name="username" label="username" type="text"></Input>
          <Input name="password" label="password" type="password"></Input>
          <Dropdown></Dropdown>
          <Button type="submit">Continue</Button>
          <div>
            <TextButton>Already have an account?</TextButton>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Register;
